var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"연결이 실패했다고요?","JPN":"連結に失敗した？","ENG":"Did you say the connection failed?","TWN":"連接失敗了？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"응, 증폭터널의 에너지 순환이 완전히 막혔어.","JPN":"うん、増幅トンネルのエネルギー循環が完全に塞がれちゃってる。","ENG":"Yeah. The energy circulation in the amplification tunnel has completely stopped.","TWN":"嗯，增幅隧道的能量循環完全被堵住了。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"터널이 막혔다는 건, 가운데 불순물이 끼었다는 뜻일까요?","JPN":"トンネルが塞がっているということは、中に不純物がつかえているってことでしょうか？","ENG":"If the tunnel is blocked, does that mean something got lodged in the middle?","TWN":"隧道被堵住，是中間卡了雜質的意思嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇지 않아도 방금 전에 탐지 드론을 보냈는데, 터널의 중간지점에서 고밀도 에너지가 확산 중인 걸 포착했어.","JPN":"さっき探知ドローンを送ったんだが、トンネルの中間地点から高密度のエネルギーが拡散している様子が捕捉された。","ENG":"We just sent a detection drone. It picked up high-density energy spreading from the tunnel's midpoint.","TWN":"我剛才已經派了探測無人機，在隧道中段偵測到高密度能量擴散中。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아무래도 터널이 외부의 간섭을 받고 있는 것 같아.","JPN":"どうやらトンネルが外部からの干渉を受けているようだ。","ENG":"It looks like the tunnel is being interfered with from the outside.","TWN":"看來隧道正受到外部干擾。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"반대쪽도 곤란하겠네요. 우연히 침식체 걸까요?","JPN":"あちらも困っているでしょうね。たまたま入り込んだ侵食体でしょうか？","ENG":"Then the other side must be having trouble too. Could it be a stray C.O.?","TWN":"另一邊肯定也很困擾吧。會不會只是偶然出現的侵蝕體？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체는 아닐 거야. 차원압력이란 게 출입로도 아닌 곳으로 뚫고 들어올 정도로 만만한 게 아니거든.","JPN":"侵食体ではないはずだ。次元圧力というものは、出入口じゃないところから割って入れるような甘いものではない。","ENG":"Probably not. Dimensional pressure isn't something that can just punch through somewhere that isn't an entry point.","TWN":"不可能是侵蝕體，次元壓力可不是隨便就能從沒有出入口的地方鑽入。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 것들이 터널을 막을 정도의 규모라면, 특정 의도가 개입한 거라고 봐야겠지.","JPN":"トンネルを塞ぐほどの規模なら、特定の意図が介入したと考えた方がいい。","ENG":"If something big enough to block the tunnel appeared, we should assume there's deliberate intent behind it.","TWN":"如果有東西能堵住整條隧道，那就代表背後有明確的意圖。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"타기리온이군요.","JPN":"タギリオンですね。","ENG":"Thagirion.","TWN":"是塔基里翁。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그자에겐 어디로든 횡단할 수 있는 황금나무의 뿌리가 있고, 당신들을 방해할 이유도 명확하니까요.","JPN":"あの者にはどこにでも横断できる黄金の木の根があって、あなたたちを邪魔するはっきりとした理由もあります。","ENG":"She has the roots of the Golden Tree that can cross anywhere, and she has every reason to interfere with you.","TWN":"她擁有能橫跨任何地方的黃金樹根，也有充分理由阻止你們。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"과거와 현재를 연결해줄 허수 에너지의 유입이 차단되면서 출력이 약해지고 있어.","JPN":"過去と現在を繋いでくれる虚数エネルギーの流入が遮断されて、出力が弱まってる。","ENG":"With the inflow of Imaginary Energy meant to connect the past and present cut off, the output is dropping.","TWN":"連接過去與現在的虛空能量流入被切斷，輸出正在下降。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이대로라면 얼마 못 가 터널의 연결 자체가 끊어지고 말 거야.","JPN":"このままじゃすぐにトンネルの連結そのものが断たれちゃう。","ENG":"At this rate, the tunnel connection itself won't last much longer.","TWN":"再這樣下去，用不了多久隧道連接就會斷裂。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"터널이 끊어지면 과거에 있던 사람들은 어떻게 되지?","JPN":"トンネルの連結が断たれたら、過去にいる人たちはどうなる？","ENG":"What happens to the people in the past if the tunnel is severed?","TWN":"如果隧道斷裂，在過去的人會怎麼樣？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"위상차를 견디지 못하고 소멸하거나, 버틴다면 허수공간으로 튕겨져 나가겠죠.","JPN":"位相の差に耐えられず消滅するか、耐えたとしても虚数空間に弾き飛ばされることになるでしょうね。","ENG":"They'll either be erased because they can't withstand the phase difference, or if they endure it, they'll be flung into imaginary space.","TWN":"無法承受相位差被消滅，或是撐住了，被彈進虛空空間。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 문제를 해결하려면 터널의 병목 현상을 해결할 정도로 더 많은 에너지를 주입해 터널을 확장해야 할 겁니다.","JPN":"この問題を解決するためには、トンネルのボトルネック現象を解決できるだけのエネルギーを注入して、トンネルを拡張しないといけません。","ENG":"To solve this, we'll need to inject enough additional energy to expand the tunnel enough to relieve the bottleneck.","TWN":"要解決這個問題、解除瓶頸，必須注入更多能量、擴張隧道。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그건 무리야. 지금 이것보다 더 많은 에너지를 무슨 수로 확보하겠어?","JPN":"それは無理だよ。今これより大量のエネルギーをどうやって確保するつもり？","ENG":"That's impossible. How are we supposed to secure even more energy than we already have?","TWN":"那不可能。要怎麼取得比現在更多的能量？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할 수 있어요.","JPN":"できますよ。","ENG":"We can do it.","TWN":"可以做得到。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"응? 신지아 회장님이?","JPN":"うん？　ヒメノ会長？","ENG":"Huh? Miss Shin Jia?","TWN":"嗯？沈佳會長？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"우물과 연결되어 있는 얼터니움 여과기의 수를 지금보다 다섯 배, 아니 열 배로 늘려서 증폭터널을 확장하는 거죠. 그럼 문제가 해결될 거에요.","JPN":"イドと繋がっているオルタニウムろ過機の数を今より5倍、いいえ、10倍にして増幅トンネルを拡張するんです。そうすれば問題は解決するでしょう。","ENG":"We just increase the number of Alternium filters connected to the Well by fivefold, no, tenfold, and expand the amplification tunnel. That should solve the problem.","TWN":"把與井相連的黑化永恆之金過濾器數量增加到現在的五倍……不，十倍，擴張增幅隧道。那樣就能解決問題。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"두 배만 늘리는 데도 몇 달은 걸릴 것 같은데, 그게 가능하다고?","JPN":"2倍にするだけでも数か月はかかるはずだが、可能なのか？","ENG":"It would take months just to double them. You're saying that's possible?","TWN":"光是增加到兩倍都得花幾個月，你說這做得到？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 별로 어렵지 않아요.","JPN":"はい、そこまで難しいことでもありません。","ENG":"Yes, it's not that difficult.","TWN":"可以，不算太難。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇게 요정의 힘을 마구잡이로 쓰면 당신의 정신이 망가질 거란 말은 하지 않는 건가요?","JPN":"そうやって妖精の力を使いすぎると、あなたの精神が壊れるとか言わないですよね？","ENG":"And you're not going to mention that using the fairy's power so recklessly will destroy your mind?","TWN":"難道你不打算說嗎？如果像那樣胡亂使用精靈的力量，精神會崩壞。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요.","JPN":"大丈夫です。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"세상을 지키고 싶은 사람이 이런 힘을 가지고 있다면... 누구라도 그렇게 했을 테니까.","JPN":"世界を守りたい人がこの力を持っていたら……誰でもそうしたはずですから。","ENG":"If someone who wanted to protect the world had this power... anyone would do the same.","TWN":"如果有人擁有這樣的力量，又想守護世界……任何人都會這麼做的。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇죠? 사장님?","JPN":"そうですよね？　社長。","ENG":"Right, Boss?","TWN":"對吧？老闆？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 하면 당장의 병목 현상은 해결할 수 있겠군.","JPN":"その方法なら今のボトルネック現象は解決できるだろう。","ENG":"That would solve the immediate bottleneck.","TWN":"這樣確實能暫時解決瓶頸。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 터널을 몇 배로 확장하건, 타기리온으로선 자신의 군세를 그만큼 더 투입하면 그만인 문제야.","JPN":"だがトンネルを何倍に拡張しようとも、タギリオンとしてはその分、自分の軍勢を投入すればいいだけの話だ。","ENG":"But no matter how many times we expand the tunnel, for Thagirion, it would only mean sending in that many more of her forces.","TWN":"但就算把隧道擴張好幾倍，對塔基里翁而言，只要再投入同樣數量的軍隊就行。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"병력을 투입해 소모전을 벌이는 것도, 병력이 한정된 우리에게 압도적으로 불리한 방식이지.","JPN":"兵力を投入し消耗戦を繰り広げるにしても、兵力が限定されている我々には圧倒的に不利だ。","ENG":"And if this turns into a war of attrition, that overwhelmingly favors her, since our numbers are limited.","TWN":"用兵力打消耗戰，對兵力有限的我們來說是壓倒性不利的方式。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 우리에겐, 타기리온에게는 없는 패가 하나 있네.","JPN":"だが我々には、タギリオンにはない切り札が一つある。","ENG":"But we have one card Thagirion doesn't.","TWN":"但我們有一張塔基里翁沒有的王牌。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 그 가능성에 모든 걸 걸어보고 싶군.","JPN":"私はその可能性にすべてをかけてみたい。","ENG":"And I would like to stake everything on that possibility.","TWN":"我想把一切賭在那個可能性上。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"타기리온에게 없는 거라면...?","JPN":"タギリオンにはないもの……？","ENG":"Something Thagirion doesn't have...?","TWN":"塔基里翁沒有的東西是……？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아이린 양.","JPN":"アイリーン君。","ENG":"Irene.","TWN":"艾琳小姐。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Yes?","TWN":"是？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"20년 전의 코핀 오브 타기리온을 찾아가면 거기엔 자네의 파노라마가 준비되어 있겠지?","JPN":"20年前のコフィン・オブ・タギリオンを訪ねれば、そこには君のパノラマが用意されているんだろう？","ENG":"If we go find the Coffin of Thagirion from twenty years ago, your Panorama will be prepared there, won't it?","TWN":"如果去找20年前的塔基里翁之棺，那裡應該會有你的全景準備好等著你。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};